-- ── Greenhouse ──────────────────────────────────────────────
UPDATE tools SET
  short_description = $q$Greenhouse is an enterprise applicant tracking and hiring platform for structured, AI-assisted recruiting, sourcing, and onboarding.$q$,
  pricing_model = $q$Custom/Enterprise pricing$q$,
  starting_price = $q$Custom pricing$q$,
  founded_year = 2012,
  company_size = $q$501-1,000 employees$q$,
  headquarters = $q$New York City, New York, USA$q$,
  languages = ARRAY[$q$English$q$]::text[],
  seo_meta_description = $q$Greenhouse is an enterprise applicant tracking system for structured hiring, AI-powered sourcing, interview scorecards, and recruiting analytics.$q$,
  og_description = $q$Greenhouse is an enterprise applicant tracking system for structured hiring, AI-powered sourcing, interview scorecards, and recruiting analytics.$q$,
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '69afcc2a-09a4-49b5-a478-dc5c7b9d0240';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '69afcc2a-09a4-49b5-a478-dc5c7b9d0240' AND logo IS NULL AND website IS NOT NULL;









