INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Digital product hosting & delivery$q$, $q$Upload files once and Gumroad handles secure hosting, download links, and delivery to buyers automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Memberships & subscriptions$q$, $q$Sell recurring access to content or communities with built-in subscription billing and management.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Built-in checkout & product pages$q$, $q$Every product gets a hosted checkout page or embeddable button, so there is no need to build a separate storefront.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Discover marketplace$q$, $q$Products can be surfaced to shoppers browsing Gumroad's own marketplace, adding a discovery channel beyond a creator's existing audience.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Affiliate program$q$, $q$Creators can recruit affiliates to promote products and automatically split commission on resulting sales.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Merchant of record tax handling$q$, $q$Gumroad calculates, collects, and remits sales tax, VAT, and GST on behalf of sellers in many jurisdictions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$License keys for software products$q$, $q$Developers can issue and verify license keys automatically for software, plugins, and templates sold through Gumroad.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Audience & email tools$q$, $q$Collect followers and send email updates about new products or releases directly from the platform.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Sales analytics$q$, $q$A dashboard shows sales trends, top products, and payout history to help creators track performance.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$API access$q$, $q$Developers can connect Gumroad to external sites or workflows using its API for custom integrations.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$No monthly subscription fee — sellers only pay when they make a sale$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Very fast setup with no coding required to start selling$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Merchant of record status removes much of the sales tax and VAT compliance burden$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Supports a wide range of product types, from ebooks and courses to memberships and software licenses$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Discover marketplace and affiliate program offer built-in ways to reach new buyers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Per-transaction fees can add up to more than flat-fee alternatives at high sales volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Discover marketplace sales carry a notably higher fee than direct sales$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Limited design customization compared to dedicated website or storefront builders$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Not built for physical goods that require inventory and shipping management$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Fee structure has changed over the years, which can make long-term revenue planning less predictable$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$What is Gumroad used for?$q$, $q$Gumroad is used by creators to sell digital products directly to their audience, including ebooks, courses, software, memberships, art, and custom commissions, without building a separate website.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$How much does Gumroad cost?$q$, $q$Gumroad is free to join. It charges a flat fee plus a small per-transaction amount on each direct sale, with a higher fee applied to sales made through its Discover marketplace.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Does Gumroad handle sales tax?$q$, $q$Yes, Gumroad acts as a merchant of record, calculating, collecting, and remitting sales tax, VAT, and GST on qualifying sales in many countries on behalf of sellers.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Can I sell memberships or subscriptions on Gumroad?$q$, $q$Yes, Gumroad supports recurring memberships and subscriptions in addition to one-time product sales, making it usable for ongoing community or content monetization.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Is Gumroad only for digital products?$q$, $q$Gumroad is primarily designed for digital products, licenses, and services such as commissions. It is not built for managing physical inventory or shipping logistics.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Selling ebooks and online courses$q$, $q$Authors and educators upload a file or course content, set a price, and share a checkout link without building a separate website.$q$, $q$Independent authors and course creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Distributing software and license keys$q$, $q$Indie developers sell plugins, templates, or apps and use Gumroad's automatic license key generation to manage access.$q$, $q$Indie software developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Selling art and custom commissions$q$, $q$Illustrators and designers sell digital prints, brushes, or take paid commission requests directly from fans.$q$, $q$Artists and freelance creatives$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Running paid memberships$q$, $q$Newsletter writers and community builders offer recurring paid access to exclusive content or a private community.$q$, $q$Newsletter writers and community creators$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Free Account$q$, $q$$0$q$, $q$No recurring fee$q$, $q$["Unlimited products and storefront pages","No cost to sign up or list products","Basic analytics and follower tools","Pay only when a sale is made"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Direct Sales$q$, $q$10% + $0.50 per transaction$q$, $q$Per transaction$q$, $q$["Hosted checkout for products sold via your own links","Merchant of record tax handling included","License key generation for software products","Membership and subscription billing support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Discover Marketplace$q$, $q$30% per transaction$q$, $q$Per transaction$q$, $q$["Exposure to shoppers browsing Gumroad's marketplace","Search and category placement for eligible products","Same checkout and delivery infrastructure as direct sales","Optional participation, not required to sell on Gumroad"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gumroad is an e-commerce platform built for independent creators who want to sell directly to their audience without building a full storefront from scratch. Founded in 2011 by Sahil Lavingia, it started as a simple way for makers to sell a digital file with a link, and has since grown into a broader toolkit for selling ebooks, courses, software, memberships, and custom commission work. The core idea has stayed consistent: remove as much setup friction as possible between a creator finishing a product and being able to charge for it.$q$, $q$Rather than charging a recurring subscription, Gumroad's business model is built around taking a percentage of each sale a creator makes, plus a small fixed amount per transaction. This pay-as-you-earn structure removes the upfront cost of setting up a storefront, which has made Gumroad especially popular among first-time sellers, side-project builders, and creators testing a new product idea before committing to more complex infrastructure. Because there is nothing to pay until a sale actually closes, the platform carries very little financial risk for someone just getting started.$q$, $q$Over the years, Gumroad has also taken on the role of merchant of record, meaning it handles the collection and remittance of sales tax, VAT, and GST on behalf of sellers in many jurisdictions. Combined with its Discover marketplace, which surfaces products to Gumroad's own audience of shoppers, the platform positions itself as both a checkout tool and a lightweight distribution channel, rather than just a payment processor bolted onto someone else's website.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$who-gumroad-is-for$q$, $q$Who Gumroad Is For$q$, 2, ARRAY[$q$Gumroad is best suited to solo creators and small teams selling digital goods: ebook authors, online course creators, illustrators selling prints or brushes, and musicians selling beats or samples. Its low barrier to entry means someone can go from idea to a live checkout link in minutes, without touching code or paying anything until a sale actually happens. That immediacy matters most to people who are still validating whether an audience will pay for what they make.$q$, $q$Independent software developers and indie hackers also use Gumroad to sell license keys, plugins, and templates, taking advantage of its built-in licensing and download delivery. Newsletter writers and community builders lean on Gumroad's membership and subscription tools to monetize a recurring audience, while freelance artists use it to sell custom commissions and take deposits from fans without negotiating payment terms manually.$q$, $q$Because pricing scales with revenue rather than a flat subscription, Gumroad works well for anyone who wants to experiment with monetization before investing in a dedicated store, and for creators whose sales volume is inconsistent month to month. It also suits people running a single side project alongside other work, since there is no ongoing bill to justify regardless of how many products they sell.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger businesses that need deep brand customization, a fully white-labeled checkout, or a dedicated marketing website will likely find Gumroad's storefront tools too limited. It is built for simplicity, not for teams that need granular control over page design, funnels, or complex product catalogs spanning hundreds of SKUs.$q$, $q$Sellers with consistently high sales volume may also find that Gumroad's per-transaction fee adds up to more than a flat-rate payment processor or a self-hosted store with a fixed platform fee would cost over time. Businesses selling physical goods at scale, with inventory, shipping, and fulfillment needs, are also better served by dedicated e-commerce platforms built around those workflows.$q$, $q$Finally, teams that need extensive custom integrations beyond what Gumroad's API and existing tooling support, or that require multiple team members with granular permission controls, may outgrow Gumroad as their operation matures. In those cases, a more configurable commerce stack is usually a better long-term fit than trying to stretch Gumroad past its intended use.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Gumroad handles digital product delivery: uploading files, generating secure download links, and issuing license keys for software products. Sellers can bundle products, offer pay-what-you-want pricing, run limited-time discounts, and set up upsells at checkout, all from a single product dashboard without any custom development or engineering support.$q$, $q$Beyond one-time sales, Gumroad supports recurring memberships and subscriptions, giving creators a way to build predictable revenue from a community or content series. Its Discover marketplace exposes products to shoppers browsing Gumroad directly, and a built-in affiliate program lets creators recruit others to promote their products for a cut of each sale, extending reach beyond a creator's own following.$q$, $q$Gumroad also provides audience tools such as follower email collection and update broadcasts, basic sales analytics, and an API for developers who want to connect Gumroad to their own site or workflow. As a merchant of record, it additionally manages tax calculation and remittance across many countries, reducing the compliance burden that would otherwise fall on individual sellers operating internationally.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$the-gumroad-experience$q$, $q$The Gumroad Experience$q$, 2, ARRAY[$q$Setting up a first product on Gumroad is intentionally fast: creators sign up, upload a file or connect a service, set a price, and get a shareable checkout link or embeddable button within minutes. There is no separate onboarding call or lengthy approval process required to start selling, which is a big part of its appeal for creators who want to launch quickly and see whether an idea resonates.$q$, $q$The seller dashboard is straightforward, showing sales, followers, and payouts without a steep learning curve. Because Gumroad hosts the checkout itself, buyers get a consistent, trusted purchase flow across every seller's page, which can help reduce friction and abandoned carts compared to a custom-built checkout that a solo creator might otherwise have to maintain.$q$, $q$Day to day, the experience centers on the tradeoff at the heart of Gumroad's model: less setup work and no fixed cost in exchange for giving up a percentage of every sale. For creators who value speed and simplicity over deep customization, that tradeoff tends to feel worthwhile, especially in the early stages of building an audience, before the transaction volume is high enough to justify a more custom setup.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
