INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Full-service payroll$q$, $q$Automatically calculates wages, withholds taxes, and files federal, state, and local payroll taxes on the employer's behalf.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Unlimited payroll runs$q$, $q$Run regular and off-cycle payroll as often as needed without extra per-run charges on any plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Employee benefits administration$q$, $q$Offer and manage health insurance, dental, vision, and 401(k) retirement plans directly through the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Multi-state payroll support$q$, $q$Pay employees across different states with automated tax registration and filing on Plus and Premium plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Employee self-onboarding$q$, $q$New hires complete their own paperwork, tax forms, and direct deposit setup through a guided online flow.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Time tracking and scheduling$q$, $q$Track hours and build employee schedules that sync directly into payroll calculations on higher-tier plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$HR tools and compliance alerts$q$, $q$Access an employee directory, PTO tracking, document storage, and alerts for changing HR compliance requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Accounting integrations$q$, $q$Sync payroll and benefits data with accounting software such as QuickBooks and Xero to streamline bookkeeping.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Employee mobile app$q$, $q$Employees can view pay stubs, W-2s, and time-off balances and request PTO from a dedicated mobile app.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Accountant partner dashboard$q$, $q$A dedicated portal lets accountants and bookkeepers manage payroll for multiple client businesses in one place.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Automates federal, state, and local payroll tax filing, reducing compliance risk for small businesses$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Combines payroll, benefits, and HR tools in a single, easy-to-navigate dashboard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Straightforward, guided setup that doesn't require prior payroll expertise$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Unlimited payroll runs included on every plan, including off-cycle payments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Strong integrations with popular accounting software like QuickBooks and Xero$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Focused on U.S. payroll and tax compliance, so it doesn't support international employee payroll$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Per-employee monthly fees can become expensive as headcount grows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Advanced HR features like dedicated HR support are reserved for the higher-priced Premium plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$May offer more HR and benefits complexity than very small or single-founder businesses need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Not designed for large enterprises with complex, multi-entity payroll requirements$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$What does Gusto cost?$q$, $q$Gusto's plans start at $49 per month plus $6 per person for the Simple plan, with Plus and Premium tiers priced higher for additional HR, time-tracking, and support features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Does Gusto handle payroll tax filing?$q$, $q$Yes, Gusto automatically calculates, withholds, and files federal, state, and local payroll taxes on behalf of the employer as part of every plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Can Gusto pay employees in multiple states?$q$, $q$Yes, multi-state payroll is supported on Gusto's Plus and Premium plans, which include the tax registration and filing needed to pay employees across state lines.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Does Gusto offer a free trial?$q$, $q$Gusto lets businesses set up an account and explore the platform at no cost, and payment is only required once payroll is actually run, with promotional free-trial periods offered at times.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Is Gusto only for U.S. businesses?$q$, $q$Gusto's payroll, tax filing, and benefits offerings are built around U.S. employment and tax law, so it is designed for businesses paying employees within the United States.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Running payroll for a small business$q$, $q$Automate wage calculations, tax withholding, and direct deposit so founders and office managers can pay employees accurately without manual tax filing.$q$, $q$Small business owners and office managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Offering employee benefits$q$, $q$Set up and administer health insurance, dental, vision, and 401(k) plans for employees directly through the same platform used for payroll.$q$, $q$HR leads and small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Managing payroll across multiple states$q$, $q$Handle tax registration, withholding, and filing for a distributed team working in different states as a company grows and hires remotely.$q$, $q$Growing companies with distributed teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Handling payroll for multiple clients$q$, $q$Use a dedicated accountant dashboard to manage payroll, tax filings, and HR tasks across several small-business clients from one login.$q$, $q$Accountants and bookkeeping firms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Simple$q$, $q$$49/month + $6 per person$q$, $q$Monthly$q$, $q$["Full-service single-state payroll","Employee self-onboarding","Basic HR tools and document storage","Standard customer support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Plus$q$, $q$$80/month + $12 per person$q$, $q$Monthly$q$, $q$["Everything in Simple","Multi-state payroll support","Time tracking and scheduling","Next-day direct deposit","Advanced HR tools and PTO management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Premium$q$, $q$$180/month + $22 per person$q$, $q$Monthly$q$, $q$["Everything in Plus","Dedicated customer success manager","Access to certified HR experts","Proactive compliance alerts","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gusto is a cloud-based payroll, benefits, and human resources platform built specifically for small and medium-sized businesses in the United States. Originally launched as ZenPayroll before rebranding to Gusto, the company set out to simplify the notoriously complicated process of running payroll, filing taxes, and managing employee benefits for businesses that don't have a dedicated HR or payroll department. Over time it has grown from a simple payroll calculator into a broader operating system for managing people, covering everything from the first job offer to year-end tax forms.$q$, $q$At its core, Gusto automates full-service payroll, including calculating and filing federal, state, and local payroll taxes on the employer's behalf. Beyond payroll, the platform bundles health insurance, 401(k) retirement plans, workers' compensation, HR tools, time tracking, and employee onboarding into a single dashboard, positioning itself as an all-in-one back-office system rather than a single-purpose payroll processor. This consolidation is a deliberate strategy: rather than stitching together separate vendors for payroll, benefits brokerage, and HR recordkeeping, a business can manage most of its people operations from one login.$q$, $q$Gusto primarily serves businesses ranging from solo contractors and startups to companies with a few hundred employees, with pricing and features that scale as a company grows. It integrates with popular accounting software such as QuickBooks and Xero, and offers a partner program tailored to accountants and bookkeepers who manage payroll for multiple clients. That accountant-facing side of the business has become an important growth channel, since bookkeeping and CPA firms often standardize on a single payroll platform across their entire client base.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$who-gusto-is-for$q$, $q$Who Gusto Is For$q$, 2, ARRAY[$q$Gusto is well suited to small and medium-sized U.S. businesses that want to run payroll and manage HR without hiring a dedicated payroll specialist. Founders and office managers who need automated tax filing, direct deposit, and benefits administration in one place tend to get the most value from the platform, since it removes the need to track changing tax rules manually or coordinate between separate vendors.$q$, $q$It's also a strong fit for growing companies that expect to add employees across multiple states, since paid plans support multi-state payroll, employee self-onboarding, and compliance alerts as headcount and complexity increase. Businesses that want to offer competitive benefits, such as health insurance and retirement plans, without negotiating directly with brokers often appreciate Gusto's built-in benefits marketplace, which can make it easier for a small employer to offer perks typically associated with larger companies.$q$, $q$Accounting firms and bookkeepers who manage payroll for several small-business clients are another core audience, since Gusto offers an accountant partner program with a dedicated dashboard for handling multiple client accounts, along with certification and referral benefits. Remote-first and hybrid teams that need to onboard new hires quickly, without mailing paperwork back and forth, also tend to appreciate the self-service onboarding flow Gusto provides for both employees and contractors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Gusto is built around U.S. payroll and tax compliance, so businesses that need to pay employees in other countries, or that operate primarily outside the United States, will need a global payroll or employer-of-record solution instead, since Gusto's core payroll and benefits offerings are U.S.-focused and don't extend to international tax and labor law.$q$, $q$Very large enterprises with complex, multi-entity payroll needs, heavy customization requirements, or existing investments in enterprise HRIS platforms may find Gusto's feature set and pricing structure less suited to their scale compared with enterprise-grade systems designed for thousands of employees across multiple legal entities and deep configurability requirements.$q$, $q$Businesses on a very tight budget that only need the most basic contractor payments, or that already have a low-cost payroll solution they're satisfied with, may not need to switch, since Gusto's per-employee monthly fees can add up as a team grows, particularly on the higher-tier plans. Companies that only pay 1099 contractors and want the absolute lowest-cost option may also want to compare Gusto's contractor-only pricing against simpler, single-purpose contractor payment tools.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Gusto's flagship feature is full-service payroll: it calculates wages, withholds and files federal, state, and local payroll taxes, and supports unlimited payroll runs, off-cycle payments, and direct deposit, so businesses don't need to manually track changing tax rates or filing deadlines. This also extends to year-end tasks, such as generating W-2s and 1099s for employees and contractors.$q$, $q$The platform also bundles HR functionality, including employee self-onboarding, e-signature for offer letters and forms, an employee directory, PTO tracking, and compliance alerts, alongside benefits administration for health insurance, dental and vision coverage, 401(k) retirement plans, and workers' compensation, all managed from the same dashboard employees and admins already use for payroll. Custom offer letter and onboarding checklist templates help standardize the hiring process across a growing team.$q$, $q$Additional tools include time tracking and scheduling on higher-tier plans, an employee mobile app for viewing pay stubs and requesting time off, integrations with accounting platforms like QuickBooks and Xero, and, on the Premium plan, access to a dedicated customer success manager and certified HR experts for compliance questions. An open API and app marketplace also let developers and partners connect Gusto to other business software a company already relies on.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$the-gusto-experience$q$, $q$The Gusto Experience$q$, 2, ARRAY[$q$Gusto is generally known for a clean, approachable interface that doesn't require payroll expertise to use, with guided setup flows that walk new customers through adding employees, connecting bank accounts, and configuring tax details. This design philosophy extends to the employee-facing side, where staff can self-onboard, review pay stubs, and manage benefits elections without needing to email HR, and can access everything through either a web browser or the companion mobile app.$q$, $q$Customer support is delivered primarily through chat, email, and phone depending on plan tier, with Premium-plan customers getting a named customer success manager and access to certified HR professionals for more nuanced compliance questions. Many small-business owners cite this guided, human-backed support as a differentiator compared with lower-cost, self-serve payroll tools, particularly when they run into an unfamiliar state tax notice or a first-time benefits enrollment question.$q$, $q$Because Gusto positions itself as an all-in-one system rather than a single-purpose payroll tool, new customers typically spend some upfront time configuring benefits, time-tracking, and HR settings during onboarding, but this investment tends to pay off in reduced day-to-day admin work once payroll, benefits, and HR data are consolidated in one place. Over time, the day-to-day experience tends to shift from active setup toward a much lighter, largely automated approval-and-review rhythm each pay period.$q$]::text[], 4);
