INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f2610a4-32aa-4b86-8154-68ef806123a9', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Autocapture$q$, $q$Automatically records clicks, pageviews, form submissions, and taps across web and mobile as soon as the tracking snippet is installed, with no manual event instrumentation required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Retroactive event definition$q$, $q$Lets analysts define new events on top of already-captured historical data through a visual, point-and-click interface, so questions that weren't anticipated up front can still be answered.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Funnels, journeys, and retention analysis$q$, $q$Standard product analytics building blocks for visualizing where users convert or drop off, the paths they take through a product, and how well cohorts retain over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Session replay$q$, $q$Watch recordings of individual user sessions cued to specific analytics events, helping teams see exactly what happened around a friction point or drop-off.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Account analytics and engagement matrix$q$, $q$Aggregates individual user behavior up to the account level for B2B products, useful for scoring engagement and prioritizing accounts at risk of churn.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Heap Connect$q$, $q$Syncs captured event data into a data warehouse so it can be combined with other business data for custom modeling or BI reporting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Heap Activate$q$, $q$Pushes behavioral segments and audiences built in Heap out to other marketing, product, or messaging tools for targeting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Sense AI assistant$q$, $q$An AI-assisted layer for surfacing insights and helping users interpret analytics data without manually building every chart from scratch.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Chart customization and dashboards$q$, $q$Configurable charts and shareable dashboards for tracking key product metrics across teams.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$SSO and compliance certifications$q$, $q$Enterprise-friendly single sign-on support along with GDPR, CCPA, and SOC 2 compliance for organizations with strict data governance requirements.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Autocapture removes the need to pre-plan and hand-instrument every event before collecting data$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Retroactive analysis lets teams answer new questions using data collected before the question was even asked$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Point-and-click event definition makes ad hoc analysis accessible to non-technical team members$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Session replay tied to specific analytics events helps teams quickly investigate friction points$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Free tier lets small teams or early-stage products start collecting data without upfront cost$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Paid plan pricing is not publicly listed and requires a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Session-based pricing can scale up quickly as traffic grows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Advanced features like session replay and account analytics are gated behind higher tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Autocaptured raw data can require cleanup or filtering to avoid noisy, low-value events$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Post-acquisition integration with Contentsquare has introduced some product and roadmap uncertainty$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$What does 'autocapture' mean in Heap?$q$, $q$Autocapture means Heap automatically records user interactions such as clicks, pageviews, and form submissions as soon as its tracking snippet is installed, without requiring developers to manually define each event beforehand.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Can Heap analyze data from before an event was defined?$q$, $q$Yes. Because autocapture collects interaction data by default, Heap allows retroactive analysis, letting users define new events on historical data that was already captured, rather than only tracking going forward.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Is Heap free to use?$q$, $q$Heap offers a free plan covering up to a set number of monthly sessions with core analytics features and limited data history. Paid Growth, Pro, and Premier tiers unlock higher session volumes, longer data retention, and advanced features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$How much do Heap's paid plans cost?$q$, $q$Paid plans are priced based on monthly session volume and are not listed publicly; pricing for Growth, Pro, and Premier tiers requires contacting Heap's sales team for a custom quote.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Is Heap still a separate product after the Contentsquare acquisition?$q$, $q$Yes, Heap continues to operate and be sold as its own product following Contentsquare's acquisition in December 2023, while also being integrated into Contentsquare's broader experience analytics suite over time.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Diagnosing funnel drop-off$q$, $q$Use funnels built on autocaptured events to identify exactly where users abandon a signup, checkout, or onboarding flow, then use session replay to see what happened at that step.$q$, $q$Product managers and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Retroactive feature adoption analysis$q$, $q$Define new events after a feature has already launched to measure adoption and engagement using data collected since the feature went live, without needing to re-instrument tracking.$q$, $q$Product analysts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Account-level engagement scoring for B2B SaaS$q$, $q$Roll individual user activity up to the account level to identify engaged versus at-risk accounts, supporting customer success and expansion efforts.$q$, $q$Customer success and B2B SaaS teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Early-stage product-market fit exploration$q$, $q$Capture all user behavior from day one so an early-stage team can explore which actions correlate with retention or conversion before committing to a fixed analytics schema.$q$, $q$Startup founders and early product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["Up to 10,000 monthly sessions","Core analytics charts","Unlimited enrichment sources","6 months of data history","SSO support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Growth$q$, $q$From ~$3,600/year (custom quote)$q$, $q$Annual, custom$q$, $q$["Unlimited users and reports","Sense AI assistant","Chart customization and CSV exports","12 months of data history","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Pro$q$, $q$Custom quote$q$, $q$Annual, custom$q$, $q$["Account analytics and engagement matrix","Report alerts","Session replay add-on","Standard support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$Premier$q$, $q$Custom quote$q$, $q$Annual, custom$q$, $q$["Data warehouse integration (Heap Connect)","Behavioral targeting (Heap Activate)","Unlimited projects and advanced user permissions","Dedicated customer success manager","Region-specific data storage"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Heap is a digital analytics and product analytics platform built around a core idea: instead of asking teams to decide in advance which clicks, taps, and form submissions matter, it captures everything automatically the moment a tracking snippet is installed. This 'autocapture' model means product managers, analysts, and growth teams can go back later and define new events on historical data, rather than waiting weeks for engineering to add tracking and only then starting to collect data.$q$, $q$Founded in 2013 in Silicon Valley by a group of Stanford computer science graduates through Y Combinator, Heap grew into one of the more prominent independent product analytics companies before being acquired by Contentsquare in December 2023. Since the acquisition, Heap has been positioned alongside Contentsquare's experience analytics and session replay tools as part of a combined product and digital experience analytics suite, while continuing to operate and sell as the Heap product.$q$, $q$At its core, Heap answers questions like where users drop off in a funnel, which features drive retention, and how specific segments of users behave differently, all without requiring a data or engineering team to hand-write every tracking call. It's aimed at product, growth, and marketing teams at SaaS and web/mobile app companies who need self-serve behavioral analytics without a heavy up-front instrumentation project.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$who-heap-is-for$q$, $q$Who Heap Is For$q$, 2, ARRAY[$q$Heap is best suited to product managers, growth marketers, and UX researchers at SaaS companies, e-commerce platforms, and consumer or B2B web/mobile applications who need to understand user behavior without depending entirely on engineering resources. Because autocapture collects interaction data by default, non-technical team members can define and analyze new events after the fact using a point-and-click interface rather than filing a ticket for new tracking code.$q$, $q$It also fits organizations that are still discovering which metrics matter. Early-stage startups exploring product-market fit benefit from being able to ask new behavioral questions of historical data as their understanding of the product evolves, since the data was already being captured before anyone knew exactly what to look for. Growth teams running frequent onboarding or funnel experiments can similarly iterate on event definitions without redeploying tracking code each time.$q$, $q$Larger organizations that need account-level analytics for B2B products, session replay tied directly to funnel drop-off points, or integration with a data warehouse also fit well into Heap's higher tiers, which add engagement scoring, behavioral targeting, and dedicated customer success support for teams running analytics at scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams with very tight data volume or budget constraints may find Heap's session-based pricing model becomes expensive quickly once they outgrow the free tier, since paid tiers are quoted individually based on monthly session volume rather than published at a flat rate. Organizations that need firm, transparent list pricing before evaluating a tool may be frustrated by having to go through a sales conversation to get a quote for Growth, Pro, or Premier plans.$q$, $q$Companies that already rely heavily on a fully event-based, manually instrumented analytics pipeline (for example, teams deeply invested in a warehouse-first or dbt-driven analytics stack with precise, hand-defined events) may not see as much incremental value from autocapture, since much of Heap's differentiation comes from reducing instrumentation work that those teams have already built out.$q$, $q$Very small teams or solo builders with minimal traffic and simple analytics needs may also find Heap's feature set more than they need; lighter-weight or free tools focused purely on pageviews and basic conversion tracking can be a simpler fit until the product and its questions grow more complex.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Heap's foundational feature is autocapture: once the tracking snippet is installed on a web or mobile app, it automatically records clicks, pageviews, form interactions, and taps without requiring developers to manually define events in code. Paired with this is retroactive analysis, which lets analysts create new event definitions on top of already-collected historical data through a visual labeling interface, avoiding the common analytics problem of realizing too late that a key interaction was never tracked.$q$, $q$On top of the captured data, Heap provides standard product analytics building blocks: funnels, user journeys, retention charts, and dashboards for tracking product usage over time. Higher tiers add session replay that links directly to specific analytics events so teams can watch exactly what a user did around a friction point, along with account-level analytics and engagement scoring for B2B products where usage needs to be understood at the company level rather than just the individual user level.$q$, $q$Additional platform capabilities include Heap Connect for syncing data to a data warehouse, Heap Activate for pushing behavioral segments into other marketing and product tools, and an AI assistant (marketed as Sense) that helps surface insights or answer questions about the underlying data. The platform also supports SSO and standard compliance certifications like GDPR, CCPA, and SOC 2, which matter for enterprise buyers evaluating it alongside other analytics vendors.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', $q$the-heap-experience$q$, $q$The Heap Experience$q$, 2, ARRAY[$q$Getting started with Heap typically involves adding a JavaScript snippet (or mobile SDK) to a site or app, after which data begins flowing in automatically without any further setup. New users often start in the Free plan, exploring pre-built charts and defining their first custom events retroactively once they see what interactions were already captured, which shortens the time between installation and getting a usable answer to a specific question.$q$, $q$As teams move into paid tiers, the day-to-day experience shifts toward building and sharing dashboards, setting up funnels for key conversion paths, and using session replay to investigate specific drop-off points flagged by the analytics. The point-and-click event definition workflow remains central throughout, letting non-technical users adjust what's being measured without waiting on engineering, though very complex custom logic can still require some collaboration with a data or dev team.$q$, $q$Since the Contentsquare acquisition, some customers have experienced product changes as the two platforms' capabilities (digital experience analytics and product analytics) are gradually integrated, so prospective buyers evaluating Heap should confirm current roadmap and support details directly with the vendor rather than relying solely on pre-acquisition materials.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
