INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cba47027-91c4-4aeb-adf8-67c52b50f458', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Autopilot AI engine$q$, $q$An embedded reasoning engine that auto-triaged bug reports, applied labels and priority levels, and detected likely duplicate tasks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Live product specs$q$, $q$Autopilot monitored linked Slack conversations for decisions and open questions and kept a running project specification synchronized automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Flexible Lists$q$, $q$Tasks lived in customizable Lists with configurable attributes, letting teams model their own workflow rather than a fixed schema.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Multiple views$q$, $q$Kanban boards, tables, timelines, and calendar views let teams visualize the same underlying data in the format that fit each workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Custom attributes and fields$q$, $q$Teams could define their own fields for priority, status, effort, or any other dimension relevant to their process.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Slack integration$q$, $q$Two-way sync between Slack conversations and Height tasks kept discussions and ticket status aligned without manual updates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$GitHub and GitLab integration$q$, $q$Commits, branches, and pull requests could be linked directly to tasks, connecting code activity to project tracking.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Design and monitoring integrations$q$, $q$Connections to Figma and Sentry brought design handoffs and error reports directly into the task tracker.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Automation rules engine$q$, $q$Teams could script conditional automations on top of Autopilot to fit workflows the AI didn't already cover.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Cross-platform apps$q$, $q$Native desktop apps for macOS and Windows plus companion mobile apps for iOS and Android kept the tracker accessible across devices.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Fast, keyboard-first interface that felt closer to a code editor than a typical tracker$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Autopilot AI reduced manual bug triage, status updates, and backlog grooming$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Generous free plan with unlimited members and tasks for small teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Deep integrations with developer tools like GitHub, GitLab, Figma, and Sentry$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Flexible custom Lists and multiple views instead of a single rigid workflow$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$The service was shut down on September 24, 2025, and is no longer available to any customers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Smaller integration marketplace than larger competitors like Jira, Asana, or ClickUp$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Automation rules and Autopilot configuration took time to learn for teams new to the tool$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$As a small, venture-backed startup it lacked the enterprise support and longevity of bigger rivals$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Fewer third-party apps and plugins than established project management platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Is Height still available to use?$q$, $q$No. Height announced its shutdown in March 2025 and the service stopped operating on September 24, 2025. It no longer accepts new signups and existing customer data is no longer accessible.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$What was Height's Autopilot feature?$q$, $q$Autopilot was Height's embedded AI reasoning engine that auto-triaged bug reports, updated task statuses from linked Slack conversations, drafted specs, and flagged duplicate tickets.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Who founded Height and when?$q$, $q$Height was founded in 2018 by Michael Villar, who had previously co-founded Kickoff, a productivity company acquired by Stripe in 2013.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$What are good alternatives to Height?$q$, $q$Teams that used Height have commonly migrated to Linear, ClickUp, Asana, or Jira, depending on whether they prioritized a fast engineering-focused interface or broader enterprise features.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Did Height have a free plan?$q$, $q$Yes, while it was operating Height offered a free plan with unlimited members and tasks, alongside paid Team, Business, and Enterprise tiers with additional automation and administrative features.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Automated bug triage$q$, $q$Engineering teams routed incoming bug reports through Autopilot, which applied labels, priority levels, and flagged likely duplicates automatically.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Living product specifications$q$, $q$Product managers linked Slack discussion threads to tasks so Autopilot could keep a shared spec document updated with decisions as they were made.$q$, $q$Product managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Cross-functional roadmap planning$q$, $q$Teams used custom Lists, attributes, and timeline views to plan and track roadmaps spanning design, engineering, and go-to-market work.$q$, $q$Cross-functional product teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Startup backlog management$q$, $q$Early-stage startups used the free plan's unlimited members and tasks to run lightweight sprint planning and backlog grooming without per-seat costs.$q$, $q$Early-stage startup teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Unlimited members and guests","Unlimited tasks and subtasks","50MB file storage","Core Lists and views"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Team$q$, $q$$8.50/member/month ($6.99 billed yearly)$q$, $q$Monthly or yearly$q$, $q$["For teams up to 50","Cross-functional project tracking","Expanded automations","Increased file storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Business$q$, $q$$11.99/user/month$q$, $q$Monthly$q$, $q$["Company-wide autonomous workflows","Advanced Autopilot capabilities","Priority support","Expanded integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["For organizations of 500+ seats","Custom onboarding and support","Advanced security and admin controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Height was a project management and issue-tracking platform built for product and engineering teams, founded in 2018 by Michael Villar, who had previously co-founded Kickoff, a productivity company acquired by Stripe in 2013. Headquartered in New York, Height raised roughly $18.3 million in backing led by Redpoint Ventures and spent several years positioning itself as a faster, more design-forward alternative to Jira and Asana before pivoting toward autonomous, AI-driven workflows.$q$, $q$The product combined flexible task lists, custom attributes, and multiple views (Kanban boards, tables, timelines, and calendars) with a reasoning engine the team called Autopilot. Autopilot could triage incoming bug reports, update task statuses from linked Slack conversations, draft specs, and flag duplicate tickets, aiming to remove much of the manual bookkeeping that usually falls on engineering managers and product owners.$q$, $q$Height announced in March 2025 that it would shut down, and the service stopped operating on September 24, 2025. The company did not publicly detail a single cause, though community discussion pointed to intensifying competition from far better-funded rivals such as Linear, ClickUp, Asana, and Jira. This profile is retained for historical and evaluative reference; the product is no longer available to new or existing customers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$who-height-is-for$q$, $q$Who Height Is For$q$, 2, ARRAY[$q$When it was operating, Height was best suited to small and mid-sized product and engineering teams that wanted a fast, keyboard-driven alternative to heavier tools like Jira. Its free tier, which allowed unlimited members and tasks, made it attractive to early-stage startups that needed real project tracking without committing to a per-seat budget from day one.$q$, $q$Teams that valued automation over manual process also gravitated toward Height. Engineering managers who were tired of manually triaging bug reports or updating ticket statuses after every Slack thread found real value in Autopilot's ability to handle that legwork, and design-conscious teams appreciated the polished, minimal interface over the denser, form-heavy screens common in older enterprise trackers.$q$, $q$Because Height integrated with GitHub, GitLab, Figma, Sentry, and Slack, it particularly suited software teams whose workflows already lived across those tools and who wanted a single tracker to sit at the center of that stack rather than a generic to-do list. Remote-first teams also liked that Autopilot could keep a shared spec up to date automatically, reducing the coordination overhead that distributed teams usually feel most acutely.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Anyone evaluating project management software today should avoid relying on Height, since the company shut down operations on September 24, 2025, stopped accepting new signups, and is no longer accessible to existing customers. Teams researching this profile for historical context should look at active alternatives such as Linear, ClickUp, Asana, or Jira instead.$q$, $q$Large enterprises that need long-term vendor stability, dedicated account management, and guaranteed longevity were poorly served even while Height was live, since it was a small, venture-backed startup without the scale of its bigger competitors. Its eventual shutdown underscores that risk for any team choosing a niche, venture-funded tool over an established incumbent for mission-critical workflows.$q$, $q$Organizations that depend on a deep marketplace of third-party plugins and integrations would also have found Height limiting; its integration list, while solid for engineering workflows, was materially smaller than what Jira, Asana, or ClickUp offer through their app ecosystems. Compliance-heavy industries requiring extensive audit trails or dedicated data-residency controls were similarly a poor fit for a lean startup product.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Height's signature feature was Autopilot, an embedded AI reasoning engine that watched task activity and linked conversations to automate routine project management chores. It could auto-triage incoming bug reports, apply labels and priority levels based on ticket content, detect likely duplicate issues, and keep a running product specification synchronized with decisions made in linked Slack threads.$q$, $q$Beyond automation, Height offered the core building blocks expected of a modern tracker: customizable Lists with configurable attributes, multiple visualization modes including Kanban boards, tables, and timelines, and granular filtering and grouping so teams could build views tailored to sprints, roadmaps, or bug queues. Custom fields let teams model their own workflow states rather than being locked into a fixed schema.$q$, $q$Collaboration and integration rounded out the feature set. Height connected with Slack, GitHub, GitLab, Figma, Sentry, Notion, and Google Sheets, letting engineering activity and design handoffs flow directly into tasks. Native desktop apps for macOS and Windows, plus companion mobile apps for iOS and Android, meant the tracker could follow a team across devices rather than living only in a browser tab, and an automation rules engine let teams script their own conditional actions on top of what Autopilot already handled.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', $q$the-height-experience$q$, $q$The Height Experience$q$, 2, ARRAY[$q$Reviewers consistently praised Height's interface for its speed and keyboard-first design, which felt closer to a code editor than a typical project management tool. Actions like creating a task, switching views, or filtering a list could be done almost entirely without touching a mouse, a detail that resonated with the engineering-heavy audience the product targeted.$q$, $q$The onboarding experience emphasized flexibility: new workspaces started with a blank canvas of Lists that teams could shape to their own process, rather than forcing a rigid methodology. This won Height a loyal following among startups and small teams who found heavier competitors like Jira cumbersome to configure and slow to use day to day.$q$, $q$That same small-team ethos, however, meant Height never achieved the scale of its rivals, and its final months were marked by a quieter cadence of product updates and social activity. The shutdown announcement in March 2025 came as a surprise to much of its user base, closing the chapter on a product that had built a genuinely devoted, if comparatively small, community around its design and automation ambitions.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
