INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('711daa05-d514-411e-aebb-2efdcb754ed0', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Dynos$q$, $q$Lightweight, isolated Linux containers that run your application's web, worker, or one-off processes and scale horizontally on demand.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Buildpacks$q$, $q$Automatic detection and build scripts for languages like Ruby, Node.js, Python, Java, PHP, and Go that turn source code into a deployable slug.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Git-based deployment$q$, $q$Deploy new releases with a simple git push to Heroku, which triggers an automatic build and release without manual server configuration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Add-ons marketplace$q$, $q$A catalog of managed third-party services, including databases, caching, logging, and monitoring, that attach to an app with one command.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Heroku Postgres$q$, $q$A managed PostgreSQL database service with automated backups, follower databases, and monitoring built directly into the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Pipelines and review apps$q$, $q$Structured CI/CD workflows that promote code through development, staging, and production while spinning up temporary review environments for pull requests.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Heroku CLI$q$, $q$A command-line tool for managing apps, config variables, dynos, logs, and add-ons directly from the terminal.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Autoscaling and metrics$q$, $q$Built-in application metrics and autoscaling rules on higher-tier dynos to help maintain performance under variable traffic.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Heroku Connect$q$, $q$A synchronization service that keeps data flowing between a Heroku app's database and Salesforce, useful for teams already on the Salesforce platform.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Extremely fast, low-friction deployment workflow built around a simple git push$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Wide native language support through buildpacks, plus custom buildpacks for others$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Large add-on marketplace that removes manual setup for databases, caching, and monitoring$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Mature CI/CD tooling with pipelines, review apps, and GitHub integration$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Backed by Salesforce, giving it long-term operational stability and Salesforce ecosystem integration$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$No permanent free tier since the 2022 removal of free dynos and databases$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Costs can rise quickly compared to raw cloud infrastructure as apps scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Less granular control over underlying infrastructure than platforms like AWS or GCP$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Add-on pricing is layered on top of dyno costs, which can make total cost less predictable$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Limited support for specialized workloads such as GPU-heavy or highly custom networking setups$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Does Heroku still offer a free plan?$q$, $q$No. Heroku discontinued its free dyno and free database tiers in November 2022; the lowest-cost option today is the paid Eco plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$What programming languages does Heroku support?$q$, $q$Heroku natively supports Ruby, Node.js, Python, Java, PHP, Go, Scala, and Clojure through official buildpacks, and custom buildpacks can extend support to other languages.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Who owns Heroku?$q$, $q$Heroku has been a wholly owned subsidiary of Salesforce since Salesforce completed its acquisition of the company in early 2011.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$How does deployment work on Heroku?$q$, $q$Developers typically deploy by pushing code to a Heroku-managed git repository, which triggers an automatic build via buildpacks and releases the app to running dynos.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Is Heroku a good fit for large-scale enterprise applications?$q$, $q$It can be, especially for teams that value operational simplicity, but very large or highly specialized workloads often become more cost-effective on a raw cloud provider like AWS or Google Cloud.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Launching an MVP quickly$q$, $q$Founders and small teams deploy a working web app or API in minutes without provisioning servers or configuring infrastructure themselves.$q$, $q$Startups and indie developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Client project delivery$q$, $q$Agencies host multiple client applications with predictable git-based deployment and managed add-ons instead of building custom infrastructure for each project.$q$, $q$Digital agencies and consultancies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Salesforce-connected applications$q$, $q$Teams build custom apps on Heroku that sync data with Salesforce in near real time using Heroku Connect.$q$, $q$Salesforce-using enterprises$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Internal tools and APIs$q$, $q$Engineering teams stand up internal dashboards, APIs, and microservices without dedicating DevOps resources to manage them.$q$, $q$Internal engineering and product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Eco$q$, $q$$5/month$q$, $q$monthly$q$, $q$["1,000 shared compute hours per month across Eco dynos","Dynos sleep after inactivity to conserve hours","Good for low-traffic apps and side projects","Access to the Heroku add-ons marketplace"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Basic$q$, $q$From $7/month$q$, $q$monthly$q$, $q$["Dedicated dyno that does not sleep","Simple pricing per dyno per month","Suitable for small production or staging apps","Standard buildpack and add-on support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Standard$q$, $q$$25-$50/month per dyno$q$, $q$monthly$q$, $q$["512 MB to 1 GB RAM per dyno","Horizontal scaling across multiple dynos","Metrics and basic autoscaling support","Designed for production applications"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$Performance$q$, $q$$250-$500+/month per dyno$q$, $q$monthly$q$, $q$["Dedicated, high-memory compute (2.5 GB+ RAM)","Improved performance isolation for high-traffic apps","Advanced autoscaling and metrics","Priority support options available"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Heroku is a cloud platform-as-a-service (PaaS) founded in 2007 and acquired by Salesforce in 2010, built to let developers deploy and run web applications without managing servers, operating systems, or networking configuration directly. It abstracts infrastructure into a small set of primitives, most notably the dyno, a lightweight container that runs application processes and scales horizontally on demand.$q$, $q$The platform's signature workflow is deploying code with a simple git push, which triggers Heroku's buildpack system to detect the application's language, install dependencies, and produce a runnable slug automatically. This removes most of the manual provisioning and configuration work associated with traditional hosting or self-managed cloud infrastructure.$q$, $q$Around this core, Heroku has built an ecosystem of managed data services and third-party add-ons, covering databases, caching, logging, monitoring, and messaging, that can be attached to an app with a single command. Since discontinuing its long-standing free dyno tier in November 2022, Heroku now operates purely as a paid, usage-billed platform aimed at teams that value speed and simplicity over granular infrastructure control.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$who-heroku-is-for$q$, $q$Who Heroku Is For$q$, 2, ARRAY[$q$Heroku suits developers and small teams who want to ship a working web application or API quickly and don't want to spend engineering time on server provisioning, container orchestration, or networking setup. Solo founders and early-stage startups building an MVP often choose it specifically to avoid standing up their own DevOps practice before they have product-market fit.$q$, $q$It also fits agencies and consultancies delivering client projects in common web languages like Ruby, Node.js, Python, Java, or PHP, where predictable git-based deployment and a managed add-on catalog reduce the operational overhead of running many small client apps in parallel.$q$, $q$Because it's a Salesforce product, Heroku is a natural fit for organizations already invested in the Salesforce ecosystem, particularly through Heroku Connect, which synchronizes data between a Heroku Postgres database and Salesforce, making it appealing for teams building custom applications that need to stay in sync with CRM data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that are highly cost-sensitive at scale, or that already have infrastructure expertise in-house, will typically find raw cloud providers like AWS, Google Cloud, or DigitalOcean cheaper once traffic and resource needs grow, since Heroku's dyno and add-on pricing carries a convenience premium over comparable raw compute and managed database pricing.$q$, $q$Organizations that need deep infrastructure customization, such as custom networking topologies, specialized Kubernetes configurations, GPU workloads, or fine-grained control over underlying compute instances, will find Heroku's abstraction layer restrictive rather than helpful, since it deliberately limits what can be configured.$q$, $q$Hobbyists and students looking for a permanently free way to host small personal projects should also look elsewhere, since Heroku removed its free dyno and free database tiers in 2022; every plan today, including the low-cost Eco tier, requires a paid subscription.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Heroku's core building blocks are dynos and buildpacks: dynos are isolated containers that run web, worker, or scheduled processes, while buildpacks automatically detect an app's language and dependencies to build a deployable slug, supporting Ruby, Node.js, Python, Java, PHP, Go, Scala, and Clojure out of the box, with custom buildpacks available for other stacks.$q$, $q$The Heroku Add-ons marketplace lets teams attach managed services, such as Heroku Postgres, Heroku Redis, logging tools, monitoring dashboards, and email or search providers, to an app with a single CLI command, avoiding the need to separately provision and maintain these services.$q$, $q$Heroku Pipelines, review apps, and GitHub integration support a structured CI/CD workflow, automatically spinning up temporary staging environments for pull requests and promoting builds through development, staging, and production stages, while the Heroku CLI and dashboard give developers command-line and visual control over scaling, config variables, logs, and releases.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('34fac46a-38d6-4512-b24c-19e0f5439125', $q$the-heroku-experience$q$, $q$The Heroku Experience$q$, 2, ARRAY[$q$Day to day, using Heroku feels centered on the terminal: developers configure environment variables, scale dynos, and tail logs through the Heroku CLI, while the web dashboard offers a visual layer for managing add-ons, collaborators, and pipeline stages across multiple apps.$q$, $q$The platform's biggest strength is how little ceremony stands between writing code and having it running in production; a working app can typically be live within minutes of a first deploy, and add-ons remove much of the friction of wiring up a database or logging service.$q$, $q$The trade-off many teams eventually feel is cost and flexibility as usage grows: dyno and add-on pricing scales in fairly large steps rather than smoothly, and once workloads become large or specialized enough, teams often start evaluating whether the operational simplicity Heroku provides still outweighs the price premium over managing infrastructure directly on a hyperscale cloud provider.$q$]::text[], 4);
